#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    char s[100005];
    while(T--){
        scanf("%s",s);
        int n=strlen(s);
        int l=0,r=n-1; int pal=1;
        while(l<r){ if(s[l]!=s[r]){pal=0;break;} l++;r--; }
        if(n==0) printf("0\n");
        else if(pal) printf("1\n");
        else printf("2\n");
    }
    return 0;
}

