import sys

def is_pal(s):
    return s == s[::-1]

def main():
    data=sys.stdin.read().split()
    if not data: return
    T=int(data[0])
    out=[]
    idx=1
    for _ in range(T):
        s=data[idx]; idx+=1
        if not s:
            out.append('0')
        elif is_pal(s):
            out.append('1')
        else:
            out.append('2')
    sys.stdout.write('\n'.join(out))

if __name__=='__main__':
    main()

